// Format the user's memory list for a Discord reply. Empty list gets a
// friendly note instead of a blank message.
const rows = $input.all().map(i => i.json);
const router = $('Channel Router').first().json;

if (!rows.length || (rows.length === 1 && !rows[0].id)) {
  return [{ json: { ...router, commandReply: 'You don\'t have any saved memories yet. Use `/remember <text>` to add one.' } }];
}

const lines = rows.map(r => {
  const scope = r.scope === 'user' ? 'global' : `#${r.channel_name}`;
  return `\`#${r.id}\` (${scope}) — ${r.content}`;
});

let out = '**Your memories:**\n' + lines.join('\n');
if (out.length > 1900) out = out.slice(0, 1900) + '\n… (truncated — run `/memories` after pruning with `/forget`)';

return [{ json: { ...router, commandReply: out } }];

// Build the Replicate API input payload for /image, auto-detecting img2img.
//
// Upstream refs:
//   Channel Router             — imagePrompt, imageHd, channelId, etc.
//   Merge Attachment Branches  — content_blocks (resolved uploads from Fetch Attachment)
//
// Behavior:
//   - /image <prompt>              → text-to-image, flux-schnell
//   - /image --hd <prompt>         → text-to-image, flux-pro
//   - /image <prompt>   + image    → image-to-image, flux-schnell (prompt_strength 0.8)
//   - /image --hd <prompt> + image → image-to-image, FALLBACK to flux-schnell.
//       Reason: flux-pro's img2img support via Replicate's model endpoint has
//       been inconsistent; flux-schnell reliably accepts the `image` input.
//       flux-dev would be the other fallback but isn't wired in the current
//       workflow. If/when flux-pro img2img is verified working, flip this.
//   - PDF attachments are ignored in the image branch.
//   - Multiple images: use the first only.
//   - Empty prompt: return error=need_prompt so the downstream IF can reply
//     with usage help instead of calling Replicate.
const router = $('Channel Router').first().json;
const contentBlocks = ($('Merge Attachment Branches').first().json || {}).content_blocks || [];
const firstImage = contentBlocks.find(b => b && b.type === 'image') || null;

const prompt = (router.imagePrompt || '').trim();
const isHd = router.imageHd === true;
const isImg2Img = !!firstImage;

if (prompt.length === 0) {
  const replyText = isImg2Img
    ? 'Please include a prompt describing what you want to generate from the reference image. Example: `/image a watercolor painting` with your photo attached.'
    : 'Usage: `/image <prompt>` — add `--hd` at the start for a slower, higher-quality render.';
  return [{
    json: {
      ...router,
      error: 'need_prompt',
      commandReply: replyText,
    }
  }];
}

let replicateModel;
let hdFallbackNote = '';
if (isImg2Img && isHd) {
  replicateModel = 'flux-schnell';
  hdFallbackNote = ' _(used Flux Schnell — `--hd` is text-only)_';
} else if (isHd) {
  replicateModel = 'flux-pro';
} else {
  replicateModel = 'flux-schnell';
}

const input = { prompt, output_format: 'png' };
if (isImg2Img) {
  input.image = `data:${firstImage.source.media_type};base64,${firstImage.source.data}`;
  input.prompt_strength = 0.8;
}

return [{
  json: {
    ...router,
    replicateModel,
    replicateInput: input,
    isImg2Img,
    isHd,
    imagePrompt: prompt,
    hdFallbackNote,
  }
}];

// Extract the Replicate prediction image URL and format a Discord reply.
// Replicate returns { output: 'https://...' } for flux-schnell/pro success,
// or { status: 'starting|processing' } if Prefer: wait timed out — in that
// case we reply with the polling URL so the user knows where to peek.
//
// When Build Replicate Input flagged img2img, prepend a note so the user
// knows their reference image was used. Append hdFallbackNote when we had
// to downgrade --hd → flux-schnell for img2img.
const router = $('Channel Router').first().json;
const built  = $('Build Replicate Input').first().json;
const res    = $input.item.json;

const isImg2Img      = built && built.isImg2Img === true;
const hdFallbackNote = (built && built.hdFallbackNote) || '';
const promptText     = (built && built.imagePrompt) || router.imagePrompt || '';

let reply;
let imageUrl = null;

if (res && res.output) {
  imageUrl = Array.isArray(res.output) ? res.output[0] : res.output;
  const kind = router.imageHd ? 'HD' : 'quick';
  const prefix = isImg2Img
    ? `🖼️ Generated from your reference image with prompt: _${promptText}_${hdFallbackNote}`
    : `🎨 (${kind}) ${promptText}`;
  reply = `${prefix}\n${imageUrl}`;
} else if (res && res.error) {
  reply = `Image generation failed: ${res.error}`;
} else if (res && res.urls && res.urls.get) {
  reply = `Image is still rendering — check back here: ${res.urls.get}`;
} else {
  reply = `Unexpected response from Replicate: \`${JSON.stringify(res).slice(0, 400)}\``;
}

return [{ json: { ...router, imageUrl, commandReply: reply } }];

// Extract Perplexity's answer + citations and format a Discord reply.
const router = $('Channel Router').first().json;
const res    = $input.item.json;

let answer = '';
try {
  answer = res.choices[0].message.content || '';
} catch (_) { answer = ''; }

const citations = Array.isArray(res.citations) ? res.citations : [];

let reply = `🔎 **${router.searchQuery}**\n\n${answer.trim()}`;
if (citations.length) {
  const cited = citations.slice(0, 5).map((u, i) => `${i + 1}. ${u}`).join('\n');
  reply += `\n\n**Sources:**\n${cited}`;
}
if (!answer) {
  reply = `Search failed: \`${JSON.stringify(res).slice(0, 400)}\``;
}
if (reply.length > 1950) reply = reply.slice(0, 1950) + '…';

return [{ json: { ...router, commandReply: reply } }];

